<!doctype html>
<html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans,sans-serif;color:#111}.brand{color:#006b5f}.box{border:1px solid #ddd;padding:16px;border-radius:8px}.row{display:flex;justify-content:space-between;margin:8px 0}</style></head><body><h1 class="brand">Pelek Properties Receipt</h1><div class="box"><p><strong>Receipt:</strong> {{ $order->id }}</p><p><strong>Guest:</strong> {{ $order->visitor_name }}</p><p><strong>Property:</strong> {{ $order->property_title }}</p><div class="row"><span>Price per night</span><strong>KES {{ number_format((float)$order->price_per_night) }}</strong></div><div class="row"><span>Days</span><strong>{{ $order->num_days }}</strong></div><div class="row"><span>Total</span><strong>KES {{ number_format((float)$order->total_amount) }}</strong></div><p><strong>Status:</strong> {{ ucfirst($order->status) }}</p></div></body></html>
